async def validate_bearer_token(
    request: Request,
    credentials: Optional[HTTPAuthorizationCredentials] = Security(bearer_scheme),
) -> TokenData:
    """
    Dependency that validates OAuth 2.0 bearer tokens.
    Extracts the token from the Authorization header, validates it against Redis,
    and returns the associated token data.
    """
    client_ip = get_client_ip(request)

    # Check rate limiting for authentication attempts
    if rate_limiter and not await rate_limiter.check_rate_limit(client_ip):
        logger.warning("Rate limit exceeded for IP: %s", client_ip)
        raise HTTPException(
            status_code=HTTP_429_TOO_MANY_REQUESTS,
            detail="Too many authentication attempts. Please try again later.",
            headers={"Retry-After": "300"},
        )

    if credentials is None:
        if rate_limiter:
            await rate_limiter.record_failure(client_ip)
        raise HTTPException(
            status_code=HTTP_401_UNAUTHORIZED,
            detail="Bearer token required",
            headers={"WWW-Authenticate": "Bearer"},
        )

    if credentials.scheme.lower() != "bearer":
        if rate_limiter:
            await rate_limiter.record_failure(client_ip)
        raise HTTPException(
            status_code=HTTP_401_UNAUTHORIZED,
            detail="Invalid authentication scheme. Bearer token required.",
            headers={"WWW-Authenticate": "Bearer"},
        )

    token = credentials.credentials

    # Basic token format validation before hitting Redis
    if not token or len(token) < 16 or len(token) > 2048:
        if rate_limiter:
            await rate_limiter.record_failure(client_ip)
        raise HTTPException(
            status_code=HTTP_401_UNAUTHORIZED,
            detail="Invalid token format",
            headers={"WWW-Authenticate": 'Bearer error="invalid_token"'},
        )

    if token_store is None:
        logger.critical("Token store not initialized")
        raise HTTPException(
            status_code=HTTP_500_INTERNAL_SERVER_ERROR,
            detail="Authentication service unavailable",
        )

    result = await token_store.validate_token(token)

    if not result.valid or result.token_data is None:
        if rate_limiter:
            await rate_limiter.record_failure(client_ip)
        # Use generic error message to avoid leaking information
        raise HTTPException(
            status_code=HTTP_401_UNAUTHORIZED,
            detail="Invalid or expired token",
            headers={"WWW-Authenticate": 'Bearer error="invalid_token"'},
        )

    return result.token_data


def require_scopes(*required_scopes: str):
    """
    Factory for creating scope-checking dependencies.
    Returns a dependency that validates the token has all required scopes.
    """
    async def scope_checker(
        token_data: TokenData = Depends(validate_bearer_token),
    ) -> TokenData:
        for scope in required_scopes:
            if scope not in token_data.scopes:
                logger.info(
                    "Insufficient scope for user %s: required=%s, has=%s",
                    token_data.user_id[:8] + "...",
                    required_scopes,
                    token_data.scopes,
                )
                raise HTTPException(
                    status_code=HTTP_403_FORBIDDEN,
                    detail="Insufficient permissions",
                    headers={
                        "WWW-Authenticate": f'Bearer error="insufficient_scope", scope="{" ".join(required_scopes)}"'
                    },
                )
        return token_data

    return scope_checker


