@app.post("/api/v1/internal/tokens", response_model=TokenCreateResponse)
async def create_token(
    request: Request,
    body: TokenCreateRequest,
    token_data: TokenData = Depends(require_scopes("admin:tokens")),
):
    """
    Internal endpoint to create tokens. Requires admin:tokens scope.
    In production, this would be handled by your OAuth authorization server.
    """
    if token_store is None:
        raise HTTPException(
            status_code=HTTP_500_INTERNAL_SERVER_ERROR,
            detail="Token store unavailable",
        )

    # Generate a cryptographically secure token
    new_token = secrets.token_urlsafe(48)

    # Validate scopes against allowlist
    allowed_scopes = {
        "read:resources",
        "write:resources",
        "admin:read",
        "admin:users",
        "admin:tokens",
    }
    validated_scopes = [s for s in body.scopes if s in allowed_scopes]

    success = await token_store.store_token(
        token=new_token,
        user_id=body.user_id,
        client_id=body.client_id,
        scopes=validated_scopes,
        ttl_seconds=body.ttl_seconds,
    )

    if not success:
        raise HTTPException(
            status_code=HTTP_500_INTERNAL_SERVER_ERROR,
            detail="Failed to create token",
        )

    logger.info(
        "Token created for user_id=%s by admin=%s",
        body.user_id[:8] + "...",
        token_data.user_id[:8] + "...",
    )

    return TokenCreateResponse(
        access_token=new_token,
        expires_in=body.ttl_seconds,
        scopes=validated_scopes,
    )


@app.post("/api/v1/token/revoke")
async def revoke_current_token(
    request: Request,
    credentials: HTTPAuthorizationCredentials = Security(bearer_scheme),
):
    """Allow a user to revoke their own token."""
    if credentials is None or not credentials.credentials:
        raise HTTPException(
            status_code=HTTP_401_UNAUTHORIZED,
            detail="Bearer token required",
            headers={"WWW-Authenticate": "Bearer"},
        )

    if token_store is None:
        raise HTTPException(
            status_code=HTTP_500_INTERNAL_SERVER_ERROR,
            detail="Token store unavailable",
        )

    # First validate the token is legitimate
    result = await token_store.validate_token(credentials.credentials)
    if not result.valid:
        raise HTTPException(
            status_code=HTTP_401_UNAUTHORIZED,
            detail="Invalid token",
            headers={"WWW-Authenticate": "Bearer"},
        )

    revoked = await token_store.revoke_token(credentials.credentials)

    if revoked:
        logger.info("Token revoked by user")
        return {"message": "Token revoked successfully"}
    else:
        raise HTTPException(
            status_code=HTTP_500_INTERNAL_SERVER_ERROR,
            detail="Failed to revoke token",
        )


